<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Sorting Algorithm Visualizer</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #111827;
      --panel: #1f2937;
      --border: #374151;
      --text: #f9fafb;
      --muted: #9ca3af;
      --bar: #38bdf8;
      --active: #f59e0b;
      --sorted: #34d399;
      --button: #2563eb;
      --button-hover: #3b82f6;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      background: radial-gradient(circle at top, #1e3a5f 0%, var(--bg) 48%);
      color: var(--text);
      font-family: Arial, Helvetica, sans-serif;
    }

    main {
      width: min(1000px, calc(100% - 32px));
      padding: 28px;
      border: 1px solid var(--border);
      border-radius: 16px;
      background: rgba(31, 41, 55, 0.92);
      box-shadow: 0 24px 70px rgba(0, 0, 0, 0.35);
    }

    h1 {
      margin: 0 0 8px;
      font-size: clamp(1.5rem, 4vw, 2.2rem);
    }

    p {
      margin: 0 0 24px;
      color: var(--muted);
    }

    #bars {
      height: 360px;
      display: flex;
      align-items: flex-end;
      gap: 4px;
      padding: 14px;
      overflow: hidden;
      border: 1px solid var(--border);
      border-radius: 12px;
      background: #0b1220;
    }

    .bar {
      flex: 1 1 0;
      min-width: 2px;
      height: 1%;
      border-radius: 5px 5px 0 0;
      background: linear-gradient(to top, #0284c7, var(--bar));
      transition: height 110ms linear, background-color 110ms linear;
    }

    .bar.active {
      background: linear-gradient(to top, #d97706, var(--active));
    }

    .bar.done {
      background: linear-gradient(to top, #059669, var(--sorted));
    }

    .controls {
      display: flex;
      flex-wrap: wrap;
      gap: 10px;
      margin-top: 20px;
    }

    button {
      border: 0;
      border-radius: 8px;
      padding: 11px 16px;
      cursor: pointer;
      color: white;
      background: var(--button);
      font-size: 0.95rem;
      font-weight: 700;
      transition: background 150ms ease, transform 150ms ease;
    }

    button:hover:not(:disabled) {
      background: var(--button-hover);
      transform: translateY(-1px);
    }

    button:disabled {
      cursor: not-allowed;
      opacity: 0.55;
    }

    #shuffle {
      background: #7c3aed;
    }

    #shuffle:hover:not(:disabled) {
      background: #8b5cf6;
    }

    #reset {
      background: #4b5563;
    }

    #reset:hover:not(:disabled) {
      background: #6b7280;
    }

    #status {
      min-height: 1.2em;
      margin-top: 16px;
      color: var(--muted);
      font-size: 0.92rem;
    }
  </style>
</head>
<body>
  <main>
    <h1>Sorting Algorithm Visualizer</h1>
    <p>Bubble sort animation — orange bars are currently being compared.</p>

    <div id="bars" aria-label="Array bars"></div>

    <div class="controls">
      <button id="sort" type="button">Sort</button>
      <button id="shuffle" type="button">Shuffle</button>
      <button id="reset" type="button">Reset</button>
    </div>

    <div id="status">Ready</div>
  </main>

  <script>
    (() => {
      const barsElement = document.getElementById("bars");
      const sortButton = document.getElementById("sort");
      const shuffleButton = document.getElementById("shuffle");
      const resetButton = document.getElementById("reset");
      const statusElement = document.getElementById("status");

      const originalArray = [42, 15, 78, 23, 91, 8, 56, 34, 67, 12, 85, 29, 73, 49, 5, 64, 37, 96, 19, 52];
      let values = originalArray.slice();
      let comparisonIndex = 0;
      let passEnd = values.length - 1;
      let running = false;
      let timer = null;
      let activeIndices = [];

      function isSorted() {
        for (let i = 1; i < values.length; i++) {
          if (values[i - 1] > values[i]) return false;
        }
        return true;
      }

      function resetSortState() {
        comparisonIndex = 0;
        passEnd = values.length - 1;
        activeIndices = [];
      }

      function render() {
        barsElement.innerHTML = "";
        const maxValue = Math.max(...values, 1);

        values.forEach((value, index) => {
          const bar = document.createElement("div");
          bar.className = "bar";
          bar.style.height = `${Math.max(2, (value / maxValue) * 100)}%`;
          bar.title = String(value);
          bar.setAttribute("aria-label", `Value ${value}`);

          if (activeIndices.includes(index)) {
            bar.classList.add("active");
          } else if (isSorted()) {
            bar.classList.add("done");
          }

          barsElement.appendChild(bar);
        });
      }

      function stopAnimation() {
        running = false;
        if (timer !== null) {
          clearInterval(timer);
          timer = null;
        }
        sortButton.disabled = false;
        shuffleButton.disabled = false;
        resetButton.disabled = false;
      }

      function setArray(newArray) {
        stopAnimation();
        values = Array.from(newArray, Number);
        resetSortState();
        render();
        statusElement.textContent = isSorted() ? "Array is sorted" : "Array set";
      }

      /*
       * One bubble-sort comparison per call.
       * Returns true only when sorting is complete.
       */
      function sortStep() {
        if (values.length < 2 || isSorted()) {
          activeIndices = [];
          render();
          return true;
        }

        if (comparisonIndex >= passEnd) {
          passEnd--;
          comparisonIndex = 0;

          if (passEnd <= 0 || isSorted()) {
            activeIndices = [];
            render();
            return true;
          }
        }

        activeIndices = [comparisonIndex, comparisonIndex + 1];

        if (values[comparisonIndex] > values[comparisonIndex + 1]) {
          const temp = values[comparisonIndex];
          values[comparisonIndex] = values[comparisonIndex + 1];
          values[comparisonIndex + 1] = temp;
        }

        comparisonIndex++;
        render();

        return isSorted();
      }

      function shuffle() {
        stopAnimation();

        for (let i = values.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [values[i], values[j]] = [values[j], values[i]];
        }

        resetSortState();
        render();
        statusElement.textContent = "Array shuffled";
      }

      function animateSort() {
        if (running) return;

        if (isSorted()) {
          render();
          statusElement.textContent = "Array is already sorted";
          return;
        }

        running = true;
        sortButton.disabled = true;
        shuffleButton.disabled = true;
        resetButton.disabled = true;
        statusElement.textContent = "Sorting...";

        timer = setInterval(() => {
          const complete = sortStep();

          if (complete) {
            stopAnimation();
            activeIndices = [];
            render();
            statusElement.textContent = "Sorting complete";
          }
        }, 85);
      }

      sortButton.addEventListener("click", animateSort);
      shuffleButton.addEventListener("click", shuffle);
      resetButton.addEventListener("click", () => {
        setArray(originalArray);
        statusElement.textContent = "Reset to original array";
      });

      window.viz = {
        array() {
          return values.slice();
        },
        setArray(a) {
          setArray(a);
        },
        sortStep() {
          return sortStep();
        },
        sorted() {
          return isSorted();
        }
      };

      render();
    })();
  </script>
</body>
</html>
